class SyncAnalysisIn(BaseModel):
    file_url: str  # URL like /ui/uploads/xyz.jpg
    prompt: Optional[str] = None  # Optional custom prompt
    media_type: Optional[str] = None  # Optional: image, video, audio (auto-detected if not provided)


@app.get("/tasks/list")
def list_tasks(operator: Optional[str] = None, all: bool = False):
    """List tasks with smart filtering.
    By default, returns only:
    - Active tasks (pending/processing)
    - Recently completed tasks (last 10 minutes)
    This dramatically reduces response size for mobile/Tailscale while still
    allowing placeholder polling to detect completions.
    Use ?all=true to get full task history.
    """
    all_tasks = task_db.get_all_tasks(operator)

    # If all=true, return everything (for debugging/admin)
    if all:
        filtered_tasks = all_tasks
    else:
        # Smart filter: active + recently completed
        from datetime import datetime, timezone, timedelta
        cutoff_time = datetime.now(timezone.utc) - timedelta(minutes=10)

        filtered_tasks = [
            t for t in all_tasks
            if t.status in ['pending', 'processing']  # Always show active
            or (
                t.status in ['completed', 'failed']  # Show recent completed
                and t.updated_at  # Has update timestamp
                and datetime.fromisoformat(t.updated_at.replace('Z', '+00:00')) > cutoff_time
            )
        ]

    return {
        "tasks": [{
            "task_id": t.task_id,
            "task_type": t.task_type,
            "status": t.status,
            "progress": t.progress,
            "created_at": t.created_at,
            "updated_at": t.updated_at,
            "result_url": t.result_url,
            "operator": t.operator,
            "prompt": t.prompt[:100] if t.prompt else None
        } for t in filtered_tasks],
        "total_tasks": len(all_tasks),
        "filtered_count": len(filtered_tasks)
    }

@app.get("/tasks/status/{task_id}")
@app.get("/tasks/{task_id}")  # Alias for MCP compatibility
def get_task_status(task_id: str):
    """Get status of a specific task"""
    task = task_db.get_task(task_id)
    if not task:
        raise HTTPException(status_code=404, detail="Task not found")

    return {
        "task_id": task.task_id,
        "task_type": task.task_type,
        "status": task.status,
        "progress": task.progress,
        "created_at": task.created_at,
        "updated_at": task.updated_at,
        "result_url": task.result_url,
        "result_data": task.result_data,
        "error_message": task.error_message
    }

@app.post("/tasks/cancel-all")
def cancel_all_stuck_tasks():
    """Cancel all pending/processing tasks by marking them as failed."""
    all_tasks = task_db.get_all_tasks()
    cancelled = 0
    for t in all_tasks:
        if t.status in (TaskStatus.PENDING, TaskStatus.PROCESSING):
            update_task(t.task_id, status=TaskStatus.FAILED, error_message="Manually cancelled by operator")
            cancelled += 1
    return {"cancelled": cancelled}

# -----------------------------------------------------------------------------
# Recent Snapshots (chronological, newest-first — for Android Timeline)
# -----------------------------------------------------------------------------
@app.get("/api/snapshots/recent")
def api_snapshots_recent(limit: int = 30, operator: str = ""):
    """Return most recent snapshots in chronological order (newest first).
    Reads from the in-memory snapshot index — lightweight, no volume parsing.
    Returns snap_id, operator, timestamp, type, and a snippet preview.
    """
    try:
        from Orchestrator.fossils import load_snapshot_index, read_volume_bytes, VOL_PATH

        index = load_snapshot_index()
        if not index:
            return {"results": [], "count": 0}

        # Filter by operator if specified
        if operator:
            items = [(sid, meta) for sid, meta in index.items() if meta.get("operator") == operator]
        else:
            items = list(index.items())

        # Sort by snap_id descending (SNAP-YYYYMMDD-NNNNN — date+seq gives chronological order)
        def sort_key(item):
            try:
                parts = item[0].split('-')
                return (int(parts[1]), int(parts[2]))
            except (ValueError, IndexError):
                return (0, 0)

        items.sort(key=sort_key, reverse=True)
        items = items[:limit]

        # Extract snippets from volume using byte offsets
        vol_bytes = read_volume_bytes(VOL_PATH) if items else b""
        # Headers/boilerplate lines to skip when extracting preview snippet
        SKIP_PREFIXES = (
            '===', 'CROSS-FILE', 'Tail', 'COUNT=', 'UFL:', 'Result:',
            'VOLUME TRACKER', 'Next:', 'TBD', '---', '===============',
            'OPERATOR:', 'TYPE:', 'SNAP-', 'TARGET_ID=',
            'Mode:', 'Timestamp:', 'Model:', 'Provider:', 'Tokens:',
            'Session:', 'Voice:', 'Backend:', 'Duration:',
            '[user]', '[assistant]', 'role:', 'content:',
        )
        import re
        # Pattern to find user message in Raw Session Log: [N] timestamp operator=X user: MESSAGE
        USER_MSG_RX = re.compile(r'\[\d+\]\s+\S+\s+operator=\S+\s+user:\s*(.+)', re.IGNORECASE)

        results = []
        for snap_id, meta in items:
            snippet = ""
            if vol_bytes:
                try:
                    start = meta.get("byte_start", 0)
                    end = meta.get("byte_end", start + 4000)
                    # Read up to 4KB to reach past headers into Raw Session Log
                    chunk = vol_bytes[start:min(end, start + 4000)].decode('utf-8', errors='replace')

                    # Strategy 1: Find user message in Raw Session Log
                    m = USER_MSG_RX.search(chunk)
                    if m:
                        snippet = m.group(1).strip()[:200]
                    else:
                        # Strategy 2: Find first line after "SNAPSHOT BODY" that isn't metadata
                        body_idx = chunk.find('SNAPSHOT BODY')
                        if body_idx >= 0:
                            lines = chunk[body_idx:].split('\n')
                            for line in lines:
                                stripped = line.strip()
                                if not stripped or len(stripped) < 15:
                                    continue
                                if any(stripped.startswith(p) for p in SKIP_PREFIXES):
                                    continue
                                if stripped.startswith('Kernel') or stripped.startswith('Context') or \
                                   stripped.startswith('- ') or stripped.startswith('Raw Session'):
                                    continue
                                snippet = stripped[:200]
                                break
                except Exception:
                    pass

            results.append({
                "snap_id": snap_id,
                "operator": meta.get("operator", ""),
                "timestamp": meta.get("timestamp", ""),
                "type": meta.get("type", "normal"),
                "snippet": snippet,
            })

        return {"results": results, "count": len(results)}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

