@app.get("/fossil/snapshot/{snap_id}")
def fossil_get_snapshot(snap_id: str):
    """Fetch full content of a single snapshot by ID."""
    try:
        from Orchestrator.fossils import get_snapshot_by_id
        result = get_snapshot_by_id(snap_id)
        if result is None:
            raise HTTPException(status_code=404, detail=f"Snapshot {snap_id} not found")
        return result
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

# -----------------------------------------------------------------------------
# Semantic Search Endpoint (for MCP)
# -----------------------------------------------------------------------------
@app.get("/fossil/hybrid")
def fossil_hybrid_search(q: str, operator: str = "", limit: int = 10):
    """Hybrid semantic + keyword search on snapshots.
    Uses Google embeddings stored in each snapshot for semantic similarity,
    combined with keyword matching for best results.
    """
    try:
        # Use semantic search with embeddings
        semantic_results = semantic_search(q, operator=operator, k=limit)

        if not semantic_results:
            return {"results": [], "message": "No results found or embeddings not available"}

        # Load index and volume for fetching content
        index = load_snapshot_index()
        vol_bytes = read_volume_bytes(VOL_PATH)

        results = []
        for snap_id, similarity in semantic_results:
            if snap_id not in index:
                continue

            meta = index[snap_id]

            # Get snippet of content
            start = meta.get("byte_start", 0)
            end = meta.get("byte_end", 0)
            snippet = ""
            if start < len(vol_bytes) and end <= len(vol_bytes):
                snap_bytes = vol_bytes[start:end]
                snap_text = snap_bytes.decode('utf-8', errors='replace')
                # Get first 500 chars as snippet
                snippet = snap_text[:500] + "..." if len(snap_text) > 500 else snap_text

            results.append({
                "snap_id": snap_id,
                "operator": meta.get("operator", "unknown"),
                "timestamp": meta.get("timestamp", ""),
                "type": meta.get("type", "normal"),
                "similarity": round(similarity, 4),
                "snippet": snippet
            })

        return {
            "query": q,
            "operator": operator or "all",
            "count": len(results),
            "results": results
        }
    except Exception as e:
        print(f"[FOSSIL] Hybrid search error: {e}")
        import traceback
        traceback.print_exc()
        raise HTTPException(status_code=500, detail=str(e))

@app.post("/analyze/audio")
async def analyze_audio(inp: AudioAnalysisIn):
    """Queue audio analysis task - Block 3"""
    try:
        task = create_task(
            TaskType.AUDIO_ANALYSIS,
            operator=inp.operator,
            input_file=inp.file_path,
            result_data={"prompt": inp.prompt}
        )
        return {
            "task_id": task.task_id,
            "status": task.status,
            "message": "Audio analysis queued"
        }
    except Exception as e:
        print(f"ERROR: Failed to queue audio analysis: {e}")
        raise HTTPException(status_code=500, detail=str(e))


